import React, { useState, useEffect, memo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ChevronLeft, ChevronRight, Star, Quote } from "lucide-react";
import { Button } from "./src/components/ui/button";
import { Card, CardContent } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const TESTIMONIALS = [
  {
    text: "Detailing Tallinnas taielikult uuel tasemel. Auto naeb valja parem kui salongist tulles.",
    author: "Marika K.",
    location: "Tallinn",
    service: "Detailing",
    source: "Google Reviews",
    rating: 5
  },
  {
    text: "Rehvitood ja sillastend said valmis sama paeva jooksul. Selgitati koik leitud vead lahti.",
    author: "Tarmo P.",
    location: "Harjumaa",
    service: "Rehvitood",
    source: "Google Reviews",
    rating: 5
  },
  {
    text: "Autodiagnostika Tallinnas, mis lopuks leidis vea, mida teised ei tuvastanud.",
    author: "Kertu L.",
    location: "Tallinn",
    service: "Autodiagnostika",
    source: "Facebook",
    rating: 5
  },
  {
    text: "Mootoriremont tehti dokumenteeritult ja koos fotodega, usaldus votis jallegi noude.",
    author: "Jaanus R.",
    location: "Saue",
    service: "Mootoritood",
    source: "WhatsApp",
    rating: 5
  },
  {
    text: "Veermiku kolin sai lahendatud kapitaalremondita. Hind jahtaigustatud kvaliteeti.",
    author: "Gerda S.",
    location: "Tallinn",
    service: "Veermik",
    source: "Email tagasiside",
    rating: 5
  },
  {
    text: "Kliimaseade ja elektritood korda jahehoojaks. Ajagraafikust peeti kinni.",
    author: "Rasmus V.",
    location: "Viimsi",
    service: "Elektritood",
    source: "Google Reviews",
    rating: 5
  },
  {
    text: "Nisbel hoiab klienti kursis iga sammu kohta. WhatsAppi fotod ja videod olid suureks abiks.",
    author: "Karolin H.",
    location: "Tallinn",
    service: "Detailing + hooldus",
    source: "WhatsApp",
    rating: 5
  },
  {
    text: "Taksopargi auto sai kiiresti hooldatud ja soidab paremini kui varem.",
    author: "Vello T.",
    location: "Maardu",
    service: "Fleet hooldus",
    source: "Google Reviews",
    rating: 5
  },
  {
    text: "DPF hooldus ja mootori puhastus toid kytusekulu alla. Soovitan.",
    author: "Indrek A.",
    location: "Tallinn",
    service: "DPF puhastus",
    source: "Email tagasiside",
    rating: 5
  },
  {
    text: "Sain uue kliendina taieliku konsultatsiooni ja selged sammud. Ei mingit ylemyyki.",
    author: "Evelin J.",
    location: "Harku",
    service: "Konsultatsioon + hooldus",
    source: "Facebook",
    rating: 5
  }
];

const TestimonialsSection = memo(() => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);

  useEffect(() => {
    if (isPaused) return;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % TESTIMONIALS.length);
    }, 5000);

    return () => clearInterval(interval);
  }, [isPaused]);

  const nextTestimonial = () => {
    setCurrentIndex((prev) => (prev + 1) % TESTIMONIALS.length);
  };

  const prevTestimonial = () => {
    setCurrentIndex((prev) => (prev - 1 + TESTIMONIALS.length) % TESTIMONIALS.length);
  };

  const goToTestimonial = (index) => {
    setCurrentIndex(index);
  };

  return (
    <Section id="testimonials" className="py-16 bg-gradient-to-br from-slate-50 to-blue-50 dark:from-slate-900 dark:to-slate-800">
      <div className="text-center mb-12">
        <motion.h2
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
          className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100 mb-4"
        >
          Mida kliendid ütlevad
        </motion.h2>
        <motion.p
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.2 }}
          viewport={{ once: true }}
          className="text-lg text-slate-600 dark:text-slate-400 max-w-2xl mx-auto"
        >
          Rohkem kui 1000 rahulolevat klienti Tallinnas ja Harjumaal
        </motion.p>
      </div>

      <div className="relative max-w-4xl mx-auto">
        <div
          className="relative"
          onMouseEnter={() => setIsPaused(true)}
          onMouseLeave={() => setIsPaused(false)}
        >
          <AnimatePresence mode="wait">
            <motion.div
              key={currentIndex}
              initial={{ opacity: 0, x: 100, scale: 0.95 }}
              animate={{ opacity: 1, x: 0, scale: 1 }}
              exit={{ opacity: 0, x: -100, scale: 0.95 }}
              transition={{ duration: 0.6, ease: "easeOut" }}
            >
              <Card className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm border-white/40 shadow-xl rounded-3xl overflow-hidden">
                <CardContent className="p-8 md:p-12">
                  <div className="flex flex-col items-center text-center">
                    <Quote className="w-12 h-12 text-[#0FB5AF] mb-6 opacity-20" />

                    <blockquote className="text-xl md:text-2xl font-medium text-slate-900 dark:text-slate-100 mb-8 leading-relaxed">
                      "{TESTIMONIALS[currentIndex].text}"
                    </blockquote>

                    <div className="flex items-center gap-1 mb-4">
                      {[...Array(TESTIMONIALS[currentIndex].rating)].map((_, i) => (
                        <Star key={i} className="w-5 h-5 fill-yellow-400 text-yellow-400" />
                      ))}
                    </div>

                    <div className="text-center">
                      <div className="font-semibold text-slate-900 dark:text-slate-100">
                        {TESTIMONIALS[currentIndex].author}
                      </div>
                      <div className="text-sm text-slate-600 dark:text-slate-400">
                        {TESTIMONIALS[currentIndex].location} • {TESTIMONIALS[currentIndex].service}
                      </div>
                      <div className="text-xs text-slate-500 dark:text-slate-500 mt-1">
                        {TESTIMONIALS[currentIndex].source}
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          </AnimatePresence>

          {/* Navigation Buttons */}
          <Button
            variant="ghost"
            size="icon"
            className="absolute left-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white shadow-lg rounded-full w-12 h-12"
            onClick={prevTestimonial}
          >
            <ChevronLeft className="w-6 h-6" />
          </Button>

          <Button
            variant="ghost"
            size="icon"
            className="absolute right-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white shadow-lg rounded-full w-12 h-12"
            onClick={nextTestimonial}
          >
            <ChevronRight className="w-6 h-6" />
          </Button>
        </div>

        {/* Dot Indicators */}
        <div className="flex justify-center gap-2 mt-8">
          {TESTIMONIALS.map((_, index) => (
            <button
              key={index}
              onClick={() => goToTestimonial(index)}
              className={`w-3 h-3 rounded-full transition-all duration-300 ${
                index === currentIndex
                  ? 'bg-[#0FB5AF] w-8'
                  : 'bg-slate-300 hover:bg-slate-400 dark:bg-slate-600 dark:hover:bg-slate-500'
              }`}
              aria-label={`Go to testimonial ${index + 1}`}
            />
          ))}
        </div>
      </div>
    </Section>
  );
});

TestimonialsSection.displayName = 'TestimonialsSection';

export default TestimonialsSection;
